const members = [
  { user_id: 4434,  avg_sessions_per_week: 6.39, days_since_last_workout: 180, revenue_at_risk_eur: 1500, churn_risk: 'high' },
  { user_id: 5844,  avg_sessions_per_week: 2.15, days_since_last_workout: 165, revenue_at_risk_eur: 1500, churn_risk: 'high' },
  { user_id: 3808,  avg_sessions_per_week: 1.89, days_since_last_workout: 142, revenue_at_risk_eur: 1500, churn_risk: 'high' },
  { user_id: 69,    avg_sessions_per_week: 1.66, days_since_last_workout: 126, revenue_at_risk_eur: 1500, churn_risk: 'high' },
  { user_id: 4101,  avg_sessions_per_week: 3.00, days_since_last_workout: 118, revenue_at_risk_eur: 1500, churn_risk: 'high' },
  { user_id: 13653, avg_sessions_per_week: 2.62, days_since_last_workout: 103, revenue_at_risk_eur: 1500, churn_risk: 'high' },
  { user_id: 16786, avg_sessions_per_week: 2.87, days_since_last_workout:  98, revenue_at_risk_eur: 1500, churn_risk: 'high' },
  { user_id: 5197,  avg_sessions_per_week: 3.49, days_since_last_workout:  90, revenue_at_risk_eur: 1500, churn_risk: 'high' }
];

// Sort by most days inactive first
const sorted = members.sort((a, b) => b.days_since_last_workout - a.days_since_last_workout);

const totalRisk = sorted.reduce((sum, m) => sum + m.revenue_at_risk_eur, 0);
const today = new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' });

return [{
  json: {
    members: sorted,
    count: sorted.length,
    totalRisk,
    today
  }
}];

const { members, count, totalRisk, today } = $input.first().json;

const top5 = members.slice(0, 5)
  .map(m => `• Member #${m.user_id} — ${m.days_since_last_workout} days inactive (${m.avg_sessions_per_week.toFixed(1)} sessions/wk)`)
  .join('\n');

const message = [
  `🚨 *Retention Alert — ${today}*`,
  ``,
  `*${count} high-risk members* need coach outreach today.`,
  ``,
  `*Top members by days inactive:*`,
  top5,
  ``,
  `💶 *Revenue at risk today: €${totalRisk.toLocaleString()}*`,
  ``,
  `_Open the dashboard to see the full list and assign coaches._`
].join('\n');

return [{ json: { message, count, totalRisk } }];
